    const id: string = req.params.id;
    const entityId = new df.EntityId(entityName, id);
    const client = df.getClient(context);

    if (req.method === 'POST') {
        // increment value
        await client.signalEntity(entityId, 'add', 1);
    } else {
        // read current state of entity
