// Weather service to fetch weather data from Open-Meteo API

export interface WeatherResult {
  Location: string;
  TemperatureC: number;
  TemperatureF: number;
  Condition: string;
  Humidity: number;
  WindSpeedKmh: number;
  Source: string;
}

export interface WeatherError {
  Location: string;
  Error: string;
  Source: string;
}

export class WeatherService {
  private readonly baseUrl = "https://api.open-meteo.com/v1/forecast";

  async getCurrentWeatherAsync(location: string): Promise<WeatherResult | WeatherError> {
    if (!location) {
      return {
        Location: "Unknown",
        Error: "Location parameter is required",
        Source: "weather-service"
      };
    }

    try {
      // Get coordinates from location name (using a simple geocoding approach)
      const coordinates = await this.geocodeLocation(location);
      if (!coordinates) {
        return {
          Location: location,
          Error: `Unable to find location: ${location}`,
          Source: "api.open-meteo.com"
        };
      }

      // Fetch weather using coordinates
      const url = `${this.baseUrl}?latitude=${coordinates.latitude}&longitude=${coordinates.longitude}&current=temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m&temperature_unit=celsius`;
      const response = await fetch(url);
      const data: any = await response.json();

      if (!data.current) {
        throw new Error("Invalid response from weather API");
      }

      const current = data.current;
      return {
        Location: location,
        TemperatureC: current.temperature_2m,
        TemperatureF: (current.temperature_2m * 9/5) + 32,
        Condition: this.getWeatherCondition(current.weather_code),
        Humidity: current.relative_humidity_2m,
        WindSpeedKmh: current.wind_speed_10m,
        Source: "api.open-meteo.com"
      };
    } catch (error) {
      return {
        Location: location,
        Error: `Failed to fetch weather: ${error instanceof Error ? error.message : String(error)}`,
        Source: "api.open-meteo.com"
      };
    }
  }

  private async geocodeLocation(location: string): Promise<{ latitude: number; longitude: number } | null> {
    try {
      const response = await fetch(
        `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(location)}&count=1&language=en&format=json`
      );
      const data: any = await response.json();

      if (data.results && data.results.length > 0) {
        const result = data.results[0];
        return {
          latitude: result.latitude,
          longitude: result.longitude
        };
      }
      return null;
    } catch (error) {
      console.error(`Geocoding error: ${error}`);
      return null;
    }
  }

  private getWeatherCondition(code: number): string {
    // WMO Weather interpretation codes
    const weatherCodes: { [key: number]: string } = {
      0: "Clear sky",
      1: "Mainly clear",
      2: "Partly cloudy",
      3: "Overcast",
      45: "Foggy",
      48: "Depositing rime fog",
      51: "Light drizzle",
      53: "Moderate drizzle",
      55: "Dense drizzle",
      61: "Slight rain",
      63: "Moderate rain",
      65: "Heavy rain",
      71: "Slight snow",
      73: "Moderate snow",
      75: "Heavy snow",
      77: "Snow grains",
      80: "Slight rain showers",
      81: "Moderate rain showers",
      82: "Violent rain showers",
      85: "Slight snow showers",
      86: "Heavy snow showers",
      95: "Thunderstorm",
